import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';
// Import danh sách mock data của bạn (sửa đường dẫn nếu dự án của bạn khác)
import { mockProducts } from '../data/mockProducts'; 

const ProductDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  
  // 1. Lấy hàm addToCart từ Context chuẩn
  const { addToCart } = useCart();

  const [product, setProduct] = useState(null);
  
  // 2. State lưu số lượng người dùng chọn (mặc định là 1 hoặc 2 tùy lúc bấm)
  const [quantity, setQuantity] = useState(1); 

  // Tìm sản phẩm theo ID khi vào trang
  useEffect(() => {
    const foundProduct = mockProducts.find((p) => p.id === parseInt(id));
    if (foundProduct) {
      setProduct(foundProduct);
    }
  }, [id]);

  // Hàm tăng số lượng khi bấm nút [+]
  const handleIncrease = () => {
    setQuantity((prev) => prev + 1);
  };

  // Hàm giảm số lượng khi bấm nút [-] (khống chế không cho giảm xuống dưới 1)
  const handleDecrease = () => {
    setQuantity((prev) => (prev > 1 ? prev - 1 : 1));
  };

  // =========================================================
  // 🛠️ CHỮA LỖI: Truyền đúng 'quantity' đang chọn vào giỏ hàng
  // =========================================================
  const handleAddToCart = () => {
    if (!product) return;
    
    // Truyền cả object sản phẩm VÀ số lượng thực tế trong state vào hàm
    addToCart(product, quantity); 

    // Kích hoạt mở nhanh thanh Sidebar giỏ hàng bên phải để người dùng nhìn thấy
    window.dispatchEvent(new Event('openCartGlobal'));
  };

  // Hàm xử lý khi bấm nút "Mua ngay"
  const handleBuyNow = () => {
    if (!product) return;
    
    // Lưu đúng số lượng người dùng chọn vào giỏ hàng
    addToCart(product, quantity); 
    
    // Chuyển hướng ngay lập tức sang trang thanh toán Checkout
    navigate('/checkout'); 
  };

  if (!product) {
    return (
      <div className="min-screen flex items-center justify-center py-20 text-gray-500">
        Đang tải dữ liệu sản phẩm...
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-white py-12 px-4">
      <div className="max-w-6xl mx-auto grid md:grid-cols-2 gap-12 items-center">
        
        {/* Bên trái: Hình ảnh sản phẩm */}
        <div className="flex justify-center bg-gray-50 rounded-3xl p-8 border border-gray-100">
          <img 
            src={product.image} 
            alt={product.name} 
            className="max-h-[400px] object-contain object-center hover:scale-105 transition-transform duration-300"
          />
        </div>

        {/* Bên phải: Thông tin & Nút bấm */}
        <div className="space-y-6">
          <div>
            <h1 className="text-3xl md:text-4xl font-extrabold text-gray-900 leading-tight">
              {product.name}
            </h1>
            <p className="text-2xl font-black text-green-600 mt-4">
              {Number(product.price).toLocaleString('vi-VN')}đ
            </p>
          </div>

          <hr className="border-gray-100" />

          {/* Cụm Mã giảm giá giả lập (Nếu giao diện của bạn có) */}
          <div className="space-y-2">
            <p className="text-sm font-bold text-gray-700">Mã giảm giá</p>
            <div className="flex flex-wrap gap-2">
              {['NLF100', 'NLF300', 'NLF500', 'NLF1000'].map((code) => (
                <span key={code} className="px-3 py-1.5 border border-dashed border-green-300 text-green-700 text-xs font-semibold rounded-lg bg-green-50/50">
                  {code}
                </span>
              ))}
            </div>
          </div>

          {/* Cụm tăng giảm số lượng hiển thị trên màn hình */}
          <div className="flex items-center gap-4 py-2">
            <span className="text-sm font-bold text-gray-700 w-20">Số lượng</span>
            <div className="flex items-center border border-gray-200 rounded-2xl bg-gray-50 p-1">
              <button 
                onClick={handleDecrease}
                className="w-10 h-10 flex items-center justify-center font-bold text-gray-600 hover:bg-white rounded-xl transition-colors cursor-pointer"
              >
                -
              </button>
              <span className="w-12 text-center font-bold text-gray-800 text-lg">
                {quantity}
              </span>
              <button 
                onClick={handleIncrease}
                className="w-10 h-10 flex items-center justify-center font-bold text-gray-600 hover:bg-white rounded-xl transition-colors cursor-pointer"
              >
                +
              </button>
            </div>
          </div>

          {/* Hai nút chức năng chính */}
          <div className="grid sm:grid-cols-2 gap-4 pt-4">
            <button
              onClick={handleAddToCart}
              className="w-full py-4 border-2 border-green-600 text-green-600 hover:bg-green-50 font-bold rounded-2xl transition-all duration-200 active:scale-[0.99] cursor-pointer"
            >
              Thêm vào giỏ hàng
            </button>
            
            <button
              onClick={handleBuyNow}
              className="w-full py-4 bg-green-600 hover:bg-green-700 text-white font-bold rounded-2xl shadow-lg shadow-green-600/20 transition-all duration-200 active:scale-[0.99] cursor-pointer"
            >
              Mua ngay
            </button>
          </div>

          <button 
            onClick={() => navigate('/')}
            className="w-full py-3 bg-gray-100 hover:bg-gray-200 text-gray-600 font-medium rounded-2xl transition-colors text-sm mt-4 cursor-pointer"
          >
            QUAY VỀ TRANG CHỦ
          </button>
        </div>

      </div>
    </div>
  );
};

export default ProductDetail;
